import { defineContract } from 'aether';

export default defineContract({
  name: 'teams',
  description: 'Manages teams, team members, and team-related operations.',

  dependencies: {
    modules: ['auth'],
  },

  exposes: {
    routes: [
      { method: 'POST', path: '/teams/:teamId/members/invite', auth: true },
      // ... other team routes
    ],
    functions: [
      'createTeam',
      'getTeamById',
      'addTeamMember',
      'removeTeamMember',
      'isTeamAdmin', // New function for admin check
      'inviteMember', // New function for inviting members
    ],
    types: ['Team', 'TeamMember', 'TeamMemberRole', 'InviteToken', 'InviteError'],
  },

  sideEffects: [
    'writes to: teams table',
    'writes to: team_members table',
    'writes to: invite_tokens table',
    'sends: invitation emails',
  ],

  invariants: [
    'A team must always have at least one admin',
    'Team members must be unique per team',
    'Invite tokens must be single-use and expire',
  ],
});
```

