import type { User } from '@auth/types';

export const TeamMemberRoleSchema = z.enum(['member', 'admin']);
export type TeamMemberRole = z.infer<typeof TeamMemberRoleSchema>;

export interface Team {
  id: string;
  name: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface TeamMember {
  userId: string;
  teamId: string;
  role: TeamMemberRole;
  joinedAt: Date;
}

export interface InviteToken {
  id: string;
  teamId: string;
  inviterId: string;
  inviteeEmail: string;
  token: string;
  expiresAt: Date;
  createdAt: Date;
  usedAt: Date | null;
  usedByUserId: string | null;
}

export type InviteError =
  | 'TEAM_NOT_FOUND'
  | 'NOT_ADMIN'
  | 'ALREADY_TEAM_MEMBER'
  | 'EMAIL_SEND_FAILED'
  | 'DATABASE_ERROR'
  | 'INVALID_INPUT';
